const DashboardPage = () => {
  const { user, logout } = useAuth();
  const location = useLocation();

  const navigation = [
    { name: 'Back to Site', href: '/', icon: ArrowLeft, external: true },
    { name: 'Dashboard', href: '/dashboard', icon: Home },
    { name: 'Profile', href: '/dashboard/profile', icon: User },
    { name: 'Settings', href: '/dashboard/settings', icon: Settings }
  ];

  const handleLogout = () => {
    logout();
  };

  // 根据用户角色显示不同的仪表盘
  const getDashboardContent = () => {
    if (!user) return <div>请先登录</div>;

    switch (user.role) {
      case 'customer':
        return <CustomerDashboard />;
      case 'vendor':
        return <VendorDashboard />;
      case 'admin':
        return <AdminDashboard />;
      default:
        return <CustomerDashboard />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="flex">
        {/* Sidebar */}
        <div className="w-64 bg-white shadow-lg min-h-screen">
          <div className="p-6">
            <a href="/" className="block mb-6">
              <h1 className="text-xl font-bold text-gray-900 hover:text-orange-600 transition-colors">Swift Fix Pro</h1>
            </a>

            <nav className="space-y-2">
              {navigation.map((item) => {
                const isActive = location.pathname === item.href && !item.external;

                if (item.external) {
                  return (
                    <a
                      key={item.name}
                      href={item.href}
                      className="flex items-center px-4 py-2 rounded-lg transition-colors text-gray-600 hover:bg-gray-100"
                    >
                      <item.icon size={20} className="mr-3" />
                      {item.name}
                    </a>
                  );
                }

                return (
                  <Link
                    key={item.name}
                    to={item.href}
                    className={`flex items-center px-4 py-2 rounded-lg transition-colors ${
                      isActive
                        ? 'bg-blue-100 text-blue-700'
                        : 'text-gray-600 hover:bg-gray-100'
                    }`}
                  >
                    <item.icon size={20} className="mr-3" />
                    {item.name}
                  </Link>
                );
              })}
            </nav>

            <div className="mt-8 pt-6 border-t">
              <button
                onClick={handleLogout}
                className="flex items-center px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg w-full"
              >
                <LogOut size={20} className="mr-3" />
                退出登录
              </button>
            </div>
          </div>
        </div>

        {/* Main Content */}
        <div className="flex-1 p-8">
          <Routes>
            <Route path="/" element={getDashboardContent()} />
            <Route path="/profile" element={<div>个人资料页面</div>} />
            <Route path="/settings" element={<div>设置页面</div>} />
          </Routes>
        </div>
      </div>
    </div>
  );
};

export default DashboardPage;
